export interface AXLineChartMessages {
  /** Message shown when no data is available */
  noData?: string;
  /** Help text shown when no data is available */
  noDataHelp?: string;
  /** Message shown when all series are hidden */
  allHidden?: string;
  /** Help text shown when all series are hidden */
  allHiddenHelp?: string;
  /** Icon for no data state */
  noDataIcon?: string;
  /** Icon for all hidden state */
  allHiddenIcon?: string;
}
